mapper.select:
SELECT 
FROM ea_archive_group g
WHERE g.id = #{id}
  AND g.deleted = 0
  AND (
    EXISTS (
        SELECT 1 FROM ea_archive_connection_permission p
        WHERE p.deleted = 0 AND p.user_id = #{userId}
          AND p.datasource_id = g.source_datasource_id
    )
    OR EXISTS (
        SELECT 1 FROM ea_archive_connection_permission p
        WHERE p.deleted = 0 AND p.user_id = #{userId}
          AND p.datasource_id = g.target_datasource_id
    )
  )

SELECT 
FROM ea_archive_group g


        AND g.enable_status = #{enableStatus}

    AND g.deleted = 0
    AND (
        EXISTS (
            SELECT 1 FROM ea_archive_connection_permission p
            WHERE p.deleted = 0 AND p.user_id = #{userId}
              AND p.datasource_id = g.source_datasource_id
        )
        OR EXISTS (
            SELECT 1 FROM ea_archive_connection_permission p
            WHERE p.deleted = 0 AND p.user_id = #{userId}
              AND p.datasource_id = g.target_datasource_id
        )
    )

ORDER BY g.group_level ASC, g.parent_id ASC, g.id DESC
